/**
 * Validates that a return URL is safe to redirect to.
 * Prevents open redirect vulnerabilities.
 */
function isValidReturnUrl(returnUrl) {
  if (!returnUrl || typeof returnUrl !== 'string') {
    return false;
  }

  // Block protocol-relative URLs (e.g., //evil.com)
  if (returnUrl.startsWith('//')) {
    return false;
  }

  // Block javascript:, data:, vbscript: and other dangerous schemes
  const dangerousSchemes = /^(javascript|data|vbscript|file):/i;
  if (dangerousSchemes.test(returnUrl.trim())) {
    return false;
  }

  // Allow relative paths (must start with /)
  if (returnUrl.startsWith('/') && !returnUrl.startsWith('//')) {
    // Ensure no CRLF injection
    if (/[\r\n]/.test(returnUrl)) {
      return false;
    }
    return true;
  }

  // For absolute URLs, validate against whitelist
  try {
    const parsed = new URL(returnUrl);

    // Check protocol
    if (!ALLOWED_PROTOCOLS.includes(parsed.protocol)) {
      return false;
    }

    // Check hostname against whitelist
    if (!ALLOWED_REDIRECT_HOSTS.includes(parsed.hostname)) {
      return false;
    }

    // Ensure no CRLF injection
    if (/[\r\n]/.test(returnUrl)) {
      return false;
    }

    return true;
  } catch (e) {
    // If URL parsing fails, it's not a valid URL
    return false;
  }
}

